Problem Statement

Sereja has a sequence of **n****a[1], a[2], ..., a[n]**&nbsp;

**n**** b[1], b[2], ..., b[n]****(1 ≤ i ≤ n)**Replace the sequence a by b, i.e., a[i] = b[i] for all i in [1, n]

&nbsp;

**k****r****k****a**&nbsp;

**a****q(r)****k****с[1], с[2], ..., с[n]****1 ≤ c[i] ≤ m****q(d) = q(r)****d****k****c**&nbsp;

code.C:
#include <stdio.h>
#include <stdint.h>

const int64_t MOD = 1000000007LL;

int64_t modPow(int64_t base, int64_t exp) {
    int64_t res = 1 % MOD;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1LL) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1LL;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t n, m, qr, k;
        scanf("%lld %lld %lld %lld", &n, &m, &qr, &k);
        printf("%lld\n", modPow(qr, k));
    }
    return 0;
}

